// Мы создаем список страниц с 0 по 4 (всего 5 страниц)
return [
  { json: { page: 0 } },
  { json: { page: 1 } },
  { json: { page: 2 } },
  { json: { page: 3 } },
  { json: { page: 4 } }
];

const monthsSV = {
  "januari": "01", "februari": "02", "mars": "03", "april": "04", "maj": "05", "juni": "06",
  "juli": "07", "augusti": "08", "september": "09", "oktober": "10", "november": "11", "december": "12",
  "sep": "09", "nov": "11", "dec": "12", "jan": "01", "feb": "02", "okt": "10"
};

for (const item of $input.all()) {
  try {
    const json = item.json;
    console.log(`Processing: ${json.title_sv}`);

    // --- ПОДГОТОВКА ТЕКСТА ДЛЯ АНАЛИЗА ---
    let rawText = ((json.title_sv || "") + " " + (json.description_sv || "")).toLowerCase();

    // --- 1. ПРОВЕРКА НА БЕСПЛАТНОСТЬ (НОВОЕ!) ---
    // По умолчанию считаем бесплатным
    json.is_free = true; 
    json.price = ""; // Очищаем цену

    // Слова, указывающие на то, что это ПЛАТНОЕ событие (еда, билеты, цены)
    const paidKeywords = [
      "julbord", "buffé", "entré", "biljett", "pris:", "kr/pers", "kostnad", 
      "meny", "servering", "avgift", "sek", "kronor"
    ];

    // Слова-исключения (если написано "fri entré" - вход свободный, даже если есть слово entré)
    const freeKeywords = ["fri entré", "gratis", "ingen avgift"];

    // Если нашли слово "платно" И НЕ нашли слово "бесплатно" -> ставим is_free = false
    if (paidKeywords.some(word => rawText.includes(word)) && !freeKeywords.some(word => rawText.includes(word))) {
        json.is_free = false;
        // Можно добавить заглушку цены, если нужно
        // json.price = "Se hemsida"; 
    }
    // ----------------------------------------

    json.approval_status = "approved"; 

    // --- 2. ГОРОД ---
    const locationLower = (json.location || "").toLowerCase();
    if (locationLower.includes("flen")) json.city = "Flen";
    else if (locationLower.includes("katrineholm")) json.city = "Katrineholm";
    else if (locationLower.includes("eskilstuna")) json.city = "Eskilstuna";
    else if (locationLower.includes("strängnäs") || locationLower.includes("strangnas")) json.city = "Strängnäs";
    else if (locationLower.includes("nyköping") || locationLower.includes("nykoping")) json.city = "Nyköping";
    else if (locationLower.includes("gnesta")) json.city = "Gnesta";
    else if (locationLower.includes("sparreholm")) json.city = "Sparreholm";
    else if (locationLower.includes("malmköping") || locationLower.includes("malmkoping")) json.city = "Malmköping";
    else if (locationLower.includes("hälleforsnäs")) json.city = "Hälleforsnäs";
    else if (locationLower.includes("vadsbro")) json.city = "Vadsbro";
    else if (locationLower.includes("årdala")) json.city = "Årdala";
    else json.city = "Flen"; 

    // --- 3. ДАТА ---
    try {
      let dateStr = (json.date || "").trim().toLowerCase(); 
      const singleMonthRange = dateStr.match(/^(\d+)\s*-\s*\d+\s+([a-zåäö]+)/i);
      if (singleMonthRange) {
          dateStr = `${singleMonthRange[1]} ${singleMonthRange[2]}`;
      } else if (dateStr.includes("-")) {
          dateStr = dateStr.split("-")[0].trim();
      }
      const parts = dateStr.split(" ");
      if (parts.length >= 2) {
        let day = parts[0].replace(/[^0-9]/g, "");
        if (day.length === 1) day = "0" + day;
        const monthName = parts[1].trim();
        const month = monthsSV[monthName];
        if (day && month) {
          const now = new Date();
          let year = now.getFullYear();
          const currentMonth = now.getMonth() + 1;
          if (parseInt(month) < currentMonth && currentMonth > 8) year = year + 1;
          json.date = `${year}-${month}-${day}`;
        } else json.date = null;
      } else json.date = null;
    } catch (e) { json.date = null; }

    // --- 4. КАТЕГОРИИ ---
    let category = "other";
    if (rawText.includes("musik") || rawText.includes("konsert") || rawText.includes("kör") || rawText.includes("jazz") || rawText.includes("allsång")) category = "music";
    else if (rawText.includes("barn") || rawText.includes("familj") || rawText.includes("sagostund")) category = "kids";
    else if (rawText.includes("mat") || rawText.includes("dryck") || rawText.includes("julbord") || rawText.includes("fika") || rawText.includes("lunch")) category = "food";
    else if (rawText.includes("sport") || rawText.includes("lopp") || rawText.includes("träning") || rawText.includes("yoga")) category = "sport";
    else if (rawText.includes("konst") || rawText.includes("utställning") || rawText.includes("bio") || rawText.includes("teater") || rawText.includes("museum")) category = "culture";
    else if (rawText.includes("verkstad") || rawText.includes("workshop") || rawText.includes("pyssel") || rawText.includes("slöjd")) category = "workshop";
    else if (rawText.includes("vandring") || rawText.includes("natur") || rawText.includes("ute") || rawText.includes("promenad")) category = "outdoors";
    json.category = category;

    // --- 5. ОПРЕДЕЛЕНИЕ ВОЗРАСТА ---
    let age_group = "all"; 
    const adultKeywords = ["18+", "18 år", "alkohol", "vin", "öl", "pub", "senior", "vuxen", "vuxna", "aw", "afterwork"];
    const teenKeywords = ["ungdom", "tonår", "13+", "15+", "högstad", "gymnas", "epa"];
    const kidsKeywords = ["barn", "familj", "knatte", "saga", "sagostund", "pyssel", "lek", "bebis", "0-", "3-"];

    if (adultKeywords.some(word => rawText.includes(word))) {
        age_group = "adults";
    } else if (teenKeywords.some(word => rawText.includes(word))) {
        age_group = "teens";
    } else if (category === "kids" || kidsKeywords.some(word => rawText.includes(word))) {
        age_group = "kids";
    }
    json.age_group = age_group;

    // Уникальный ключ и чистка
    json.unique_key = (json.title_sv || "no_title") + "_" + (json.date || "no_date");
    if (json.title_sv) json.title_sv = json.title_sv.trim();
    if (json.description_sv) json.description_sv = json.description_sv.trim();

  } catch (error) {
    console.error('Error processing event:', error);
    item.json.error = error.message;
  }
}

return $input.all();

